var smallestIndex = function(nums) {
    for (let i = 0; i < nums.length; i++) {
        let v = nums[i], s = 0;
        while (v > 0) { s += v % 10; v = Math.floor(v / 10); }
        if (s === i) return i;
    }
    return -1;
};
